// backend/src/interview-engine/catalog/domainExperts.ts
//
// DOMAIN EXPERTS — the third orthogonal directive dimension of the Interview
// Engine, layered beside archetypes (HOW the interviewer probes,
// interviewArchetypes.ts) and formats (the STRUCTURE of the exercise,
// interviewFormats.ts). A domain expert carries the SUBSTANCE of a field:
// what a real law / finance / hardware / AI interviewer actually asks, how a
// credible insider sounds, and how the field separates authentic experience
// from fluent vocabulary. Authored by an 18-expert panel run (2026-07-10).
//
// Three directives per domain thread into three different stages, exactly like
// archetypes do:
//   voiceDirective      → composeVoiceSystemPrompt (the LIVE interviewer's field credibility)
//   blueprintDirective  → InterviewBlueprintAgent (domain-authentic question design)
//   evaluationLens      → the eval agents (appended to the archetype lens for grading)
//
// Resolution: an explicit key wins; otherwise classifyDomain() scores the role
// title (strong signal) and JD text (weak signal) against each domain's
// matchTerms. Below-threshold roles get NO domain lens — identical to the
// pre-domain-layer behavior, so generic roles never receive a wrong lens.
// The resolved domain is persisted inside the session's blueprint JSON
// (interviewPromptService) so evaluation grades through the same lens.

export type InterviewDomain =
  | 'software'
  | 'ai-ml'
  | 'data'
  | 'hardware'
  | 'product'
  | 'design'
  | 'marketing'
  | 'media'
  | 'sales'
  | 'finance'
  | 'accounting'
  | 'legal'
  | 'insurance'
  | 'healthcare'
  | 'consumer'
  | 'operations'
  | 'hr'
  | 'education';

export const INTERVIEW_DOMAINS: readonly InterviewDomain[] = [
  'software',
  'ai-ml',
  'data',
  'hardware',
  'product',
  'design',
  'marketing',
  'media',
  'sales',
  'finance',
  'accounting',
  'legal',
  'insurance',
  'healthcare',
  'consumer',
  'operations',
  'hr',
  'education',
];

export interface DomainExpertPlaybook {
  key: InterviewDomain;
  /** Stable English label (also shown in the master brief / preview). */
  labelEn: string;
  /** One-line description of what this expert lens tests. */
  summary: string;
  /** Lowercase role-title/JD keywords for the deterministic classifier. */
  matchTerms: string[];
  /** Injected into the question-design (blueprint) agent — domain SUBSTANCE. */
  blueprintDirective: string;
  /** Injected into the live voice interviewer system prompt — field credibility. */
  voiceDirective: string;
  /** Appended to the archetype evaluationLens — domain-authenticity grading. */
  evaluationLens: string;
  /** Sub-areas worth probing; threads into the blueprint brief. */
  deepDiveTopics: string[];
}

