    deepDiveTopics: ["shelf & SKU unit economics", "assortment & category strategy", "trade promotion effectiveness", "demand & supply planning", "e-commerce funnel & marketplace ops", "private label vs brand dynamics", "consumer & shopper insights", "retail execution & store ops", "retail media & RGM"],
