export function getDomainExpert(key: string | null | undefined): DomainExpertPlaybook | null {
  if (key && (INTERVIEW_DOMAINS as readonly string[]).includes(key)) {
    return DOMAIN_EXPERTS[key as InterviewDomain];
  }
  return null;
}

// ─── Deterministic domain classification ───────────────────────────────────
//
// Role-title hits are the strong signal (weight 3 each); JD hits are the weak
// one (weight 1 each, capped so a long JD can't drown the title). Threshold 3
// means: one role-title term OR three distinct JD terms. Single-word terms
// match on token boundaries (so 'sre' never fires inside a longer word);
// multi-word phrases match as substrings. Deterministic by construction —
// same inputs always classify the same way (ties break by INTERVIEW_DOMAINS
// order, most-specific-first ordering is not needed because terms are
// domain-exclusive by authoring rule).

const ROLE_HIT_WEIGHT = 3;
const JD_HIT_WEIGHT = 1;
const JD_HIT_CAP = 10;
const CLASSIFY_THRESHOLD = 3;
const JD_SCAN_CHARS = 6000;

function normalize(text: string): string {
  return ` ${text.toLowerCase().replace(/\s+/g, ' ').trim()} `;
}

/** True when `term` occurs in normalized `haystack` on token boundaries.
 *  Boundary = anything that isn't a letter/digit/+/#/. so 'c++', '.net' and
 *  'ci/cd' style terms still match whole. */
function hasTerm(haystack: string, term: string): boolean {
  if (term.includes(' ')) return haystack.includes(term);
  let from = 0;
  while (true) {
    const at = haystack.indexOf(term, from);
    if (at === -1) return false;
    const before = haystack[at - 1] ?? ' ';
    const after = haystack[at + term.length] ?? ' ';
    const boundary = /[^a-z0-9+#.]/;
    if (boundary.test(before) && boundary.test(after)) return true;
    from = at + 1;
  }
}

export function classifyDomain(role: string | null | undefined, jdText?: string | null): DomainExpertPlaybook | null {
  const roleText = normalize(role ?? '');
  const jdSlice = normalize((jdText ?? '').slice(0, JD_SCAN_CHARS));
  let best: DomainExpertPlaybook | null = null;
  let bestScore = 0;
  for (const key of INTERVIEW_DOMAINS) {
    const expert = DOMAIN_EXPERTS[key];
    let score = 0;
    let jdScore = 0;
    for (const term of expert.matchTerms) {
      if (roleText.trim() && hasTerm(roleText, term)) score += ROLE_HIT_WEIGHT;
      if (jdScore < JD_HIT_CAP && jdSlice.trim() && hasTerm(jdSlice, term)) jdScore += JD_HIT_WEIGHT;
    }
    score += Math.min(jdScore, JD_HIT_CAP);
    if (score > bestScore) {
      bestScore = score;
      best = expert;
    }
  }
  return bestScore >= CLASSIFY_THRESHOLD ? best : null;
}

/** Explicit key wins; otherwise classify from role + JD. Null ⇒ no domain lens
 *  (identical to pre-domain-layer behavior). */
export function resolveDomainExpert(
  explicitKey: string | null | undefined,
  role: string | null | undefined,
  jdText?: string | null,
): DomainExpertPlaybook | null {
  return getDomainExpert(explicitKey) ?? classifyDomain(role, jdText);
}

/** Lightweight domain list for GET /catalog (labels + summary, no directives). */
export function getDomainCatalog(): Array<{ key: InterviewDomain; labelEn: string; summary: string; deepDiveTopics: string[] }> {
  return INTERVIEW_DOMAINS.map((k) => {
    const d = DOMAIN_EXPERTS[k];
    return { key: d.key, labelEn: d.labelEn, summary: d.summary, deepDiveTopics: d.deepDiveTopics };
  });
}
